const KeyboardManager={shortcuts: new Map(),listeners: new Map(),initialized: false,_init(){if(this.initialized)return;document.addEventListener('keydown',this._handleKeydown.bind(this));this.initialized=true;},register(shortcut,callback){this._init();const key=this._parseShortcut(shortcut);this.shortcuts.set(key,{shortcut,callback});},unregister(shortcut){const key=this._parseShortcut(shortcut);this.shortcuts.delete(key);},add(id,callback){this._init();this.listeners.set(id,callback);},remove(id){this.listeners.delete(id);},_handleKeydown(e){this.listeners.forEach(callback=>callback(e));const key=this._getEventKey(e);const shortcut=this.shortcuts.get(key);if(shortcut){e.preventDefault();shortcut.callback(e);}},_parseShortcut(shortcut){return shortcut.toLowerCase().trim();},_getEventKey(e){const parts=[];if(e.ctrlKey||e.metaKey)parts.push('ctrl');if(e.shiftKey)parts.push('shift');if(e.altKey)parts.push('alt');const key=e.key.toLowerCase();parts.push(key);return parts.join('+');}};export default KeyboardManager;